const blocked_item = $input.last().json.jira_issue_changelog.filter((item) => {
  return (
    // filter by labels field
    item.items[0].field == "labels" && item.items[0].toString === "blocked"
  )
})


return (
  [
    {
      json: {
        blocked_item,
        data: $input.last().json
      }
    }
  ]
)

const today = new Date();
const blocked_date = new Date($input.last().json.blocked_item[0].created)
const diff = today - blocked_date;
const blocked_days = Math.floor(diff / (1000 * 60 * 60 * 24));

return (
  [
    {
      json: {
        blocked_days,
        data: $input.last().json.data
      }
    }
  ]
)

const issues = $input.all().map((e) => {
  const new_obj = {
    key:e.json.key,
    due_date:e.json.fields.duedate,
    assignee:e.json.fields.assignee,
    labels:e.json.fields.labels
  }
  return (
    new_obj
  )
})

const issues_list = issues.filter((e) => {
  return (e.due_date != null)
})

return (
  [
    ...issues_list
  ]
);

const dueDate_string = $input.last().json.due_date;
const today_string = new Date().toISOString().split('T')[0];
const key = $input.last().json.key;
const assignee = $input.last().json.assignee;

const due = new Date(dueDate_string);
const tod = new Date()
// difftime < 0 overdue, == 0 duedate, > 0 still on date
const diffTime = due - tod;
const daysLeft = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

return [
  {
    json: {
      key,
      dueDate_string,
      today_string,
      isOverdue: daysLeft < 0 ? true : false,
      isImminent: daysLeft >= 0 && daysLeft <= 2,
      isBlocked: $input.last().json.labels.includes("blocked"),
      days_left: daysLeft,
      overdue_days: daysLeft < 0 ? daysLeft * -1 : 0,
      assignee: assignee
    }
  }
];

